var e=JSON.parse(`[{"id":"L7_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"……굉장해.","JPN":"……すごい。","ENG":"...Incredible.","TWN":"……太出乎意料了。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"그 마에스트로랑 거의 대등하게 싸우고 있어.","JPN":"あのマエストロと互角に戦っている。","ENG":"She's fighting almost on equal footing with Maestra.","TWN":"和指揮家打得不相上下。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"아직 아니야!","JPN":"まだだ！","ENG":"Not yet!","TWN":"還沒完呢！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L12_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"조금만 더……! 조금만 더 빠르게……!","JPN":"もう少し……！　もう少し速く……！","ENG":"Just a little more...! Just a little faster...!","TWN":"很好，再近一點……！再近一點就可以了……！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_ON","text":{"KOREA":"아첼레란도.","JPN":"アッチェレランド。","ENG":"Accelerando.","TWN":"漸快。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CONDUCT_HARMONY_NULL_ON","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_ON","text":{"KOREA":"한 번, 한 번의 위력 자체는 별 볼일 없지만, 리듬이 점점 빨라지고 있어요.","JPN":"一回一回の威力は大したものではありませんが、どんどんテンポが速くなっています。","ENG":"The power of each attack isn't powerful, but the rhythm is getting faster.","TWN":"每一擊的威力本身並沒有什麼特別，但是節奏卻越來越快。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CONDUCT_HARMONY_NULL_ON","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_ON","text":{"KOREA":"공간을 도약해, 회피와 공격이 거의 동시에 이루어지는 게 무척 인상 깊네요.","JPN":"空間を跳躍し、回避と攻撃をほぼ同時に行なう動きがとても印象的ですね。","ENG":"It is impressive how you do space jump to evade and attack almost simultaneously.","TWN":"令人印象深刻的是，你可以空間跳躍，幾乎同時進行閃避和攻擊兩種動作。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CONDUCT_HARMONY_NULL_ON","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"시끄러워!! 난 싸우면서 쫑알쫑알 입 터는 자식들이 제일 싫다고……!","JPN":"うるさい！！　アタシは口数の減らない奴が大嫌いなんだ！！","ENG":"Shut it!! I hate jerks like you who keep yapping when they fight...!","TWN":"閉嘴！！我討厭打架時念個沒完的傢伙……！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CONDUCT_HARMONY_NULL_ON","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L21_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"환상종이니 뭐니……!! 그딴 거 내가 알 게 뭐야!!","JPN":"幻想種だのなんだの……！！　そんなもん知るか！！","ENG":"Bygone or not...! Why should I care?!","TWN":"夢幻品種什麼的……！！我才不管那麼多呢！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CONDUCT_HARMONY_NULL_ON","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"덤벼!! 난 그저 내가 가진 걸 전부 너한테 때려 박을 뿐이야!","JPN":"かかってこい！！　アタシはアタシが持ってるすべてをおまえにぶつけてやる！","ENG":"Come at me!! Because all I can do is hit you with everything I've got!","TWN":"來啊！！我會用我所能用上的一切打倒你！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CONDUCT_HARMONY_NULL_ON","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L26_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"안 돼, 절묘하게 힘의 균형이 맞아 있는 상태야.","JPN":"ダメ、絶妙に力のバランスが取れている状態だ。","ENG":"No, both of their powers are exquisitely balanced.","TWN":"不，現在兩邊的力量達到了微妙的平衡。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CONDUCT_HARMONY_NULL_ON","face":"UNIT_IDLE"},"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L27_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"섣부르게 도우려고 하다간, 오히려 앨리스에게 방해가 될지도 몰라.","JPN":"ここで下手に手を出したら、アリスの邪魔になりかねない。","ENG":"So if I try to hastily help her, I might actually get in her way.","TWN":"如果我太急於幫忙，反而可能成為艾莉絲的絆腳石。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CONDUCT_HARMONY_NULL_ON","face":"UNIT_IDLE"},"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"하지만 카운터 능력을 각성했다고 해도…… 앨리스는 이미 한계의 한계를 넘은 상태.","JPN":"でもカウンター能力に目覚めたとはいえ……アリスはすでに限界を超えている。","ENG":"But even if she awakened her Counter ability... Alice has already broken through her limits.","TWN":"但就算覺醒了制裁者能力……艾莉絲已經超出了她​​的極限。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CONDUCT_HARMONY_NULL_ON","face":"UNIT_IDLE"},"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"균형이 조금이라도 깨지는 순간, 마에스트로 쪽으로 기울게 될 거야.","JPN":"バランスが少しでも崩れたら、形勢は一瞬でマエストロが有利になるはず。","ENG":"The moment the balance is fractured by the smallest amount, it will be in Maestra's favor.","TWN":"一旦平衡受到輕微的干擾，指揮家就會佔上風。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CONDUCT_HARMONY_NULL_ON","face":"UNIT_IDLE"},"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"그렇게 되면…….","JPN":"そうなってしまったら……","ENG":"Then...","TWN":"那樣的話……"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CONDUCT_HARMONY_NULL_ON","face":"UNIT_IDLE"},"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_DESPAIR"},"R":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"……그것만큼은 막아야 해.","JPN":"それだけは防がないと。","ENG":"...I need to stop that from happening at all costs.","TWN":"……不，不會的。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CONDUCT_HARMONY_NULL_ON","face":"UNIT_IDLE"},"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_LIGHT_02"},{"id":"L34_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"앨리스가 그런 비참한 미래에 다다르지 못하도록. 내가 막겠어.","JPN":"アリスがあんな悲惨な未来を迎えないために、私が防いでみせる。","ENG":"I'll prevent Alice from facing a dismal future.","TWN":"這種情況是不會出現的。因為我會阻止它。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CONDUCT_HARMONY_NULL_ON","face":"UNIT_IDLE"},"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"젠장, 이렇게 잽만 날려서는 승부가 안 나……!","JPN":"くそ、ジャブだけじゃ止めを刺すことができない……！","ENG":"Gah, I'm not going to win by throwing jabs...!","TWN":"可惡，這種力量的拳頭根本贏不了……！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L40_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"조금 더 빨리 가속해서……! 조금 더 강한 위력으로 한 방을 날려야 해……!","JPN":"もうちょっと加速して……！　もっと強い一発を食らわせないと……！","ENG":"I need to accelerate faster...! I need to throw a punch with a little more power...!","TWN":"再速度快一點……！我需要打出更強的一拳……！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"좋아, 여기서는 어퍼로……!","JPN":"よし、ここではアッパーで……！","ENG":"Okay, an uppercut here–!","TWN":"好，這裡上勾拳……！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"읏!? 건틀렛의 출력이……!?","JPN":"うっ！？　ガントレットの出力が……！？","ENG":"Ngh?! The gauntlet's output is...?!","TWN":"呃？！拳套的輸出……？！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_MECHANIC_WORK_07"},{"id":"L47_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_ON","text":{"KOREA":"마침내, 틈을 보이시는 군요.","JPN":"やっと、隙を見せましたね。","ENG":"Finally, you show weakness.","TWN":"終於，找到你的破綻了。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CONDUCT_HARMONY_NULL_ON","face":"UNIT_PRIDE"}}}},{"id":"L48_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_ON","text":{"KOREA":"나쁘지 않은 연주였습니다만, 이제 끝을 내겠습니다.","JPN":"悪くない演奏でしたが、そろそろ終わりにしましょう。","ENG":"It was not a bad performance, but I will end it now.","TWN":"演奏不算糟糕，但很遺憾我要在這裡結束它了。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CONDUCT_HARMONY_NULL_ON","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"하으으윽……!! ","JPN":"はうううっ……！！ ","ENG":"HAAAAAGH...!!","TWN":"呃啊啊啊……！！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L2_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"하아, 하아, 하아……!","JPN":"はあ、はあ、はあ……！","ENG":"*Huff* *Huff* *Huff*","TWN":"哈啊，哈啊，哈啊……！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"부전대장!!","JPN":"副戦隊長！！","ENG":"Deputy Commander!!","TWN":"副戰隊長！！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_DESPAIR"},"R":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_SERIOUS"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L4_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"괜찮아!? 젠장!! 왜 끼어든 거야……!!","JPN":"大丈夫か！？　くそ！！　なんで入って来たんだ……！！","ENG":"Are you all right?! Dammit!! Why did you do that...?!","TWN":"你還好嗎！？該死的！！你過來做什麼……！！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_DESPAIR"},"R":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"그야, 넌 여기서 죽으면 안 되니까…….","JPN":"それはもちろん、あなたにここで死なれたら困るから……","ENG":"Because... I can't let you die here...","TWN":"因為，你不能死在這裡……"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L7_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"후후……. 넌 야크샤의 전대장이 될 몸이잖아……?","JPN":"ふふ……あなたは、ヤクシャーの戦隊長になる人でしょう……？","ENG":"Fu fuu... You're supposed to become the Yaksha's Commander, remember...?","TWN":"呵呵……你是註定要成為夜叉戰隊長的人……"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"그러니까……!","JPN":"だから……！","ENG":"So...!","TWN":"所以……！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_ON","text":{"KOREA":"한 번에 마무리를 짓지 못한 건 아쉽지만.","JPN":"まとめて片付けられなかったのは残念ですが。","ENG":"It is a pity I could not finish you with one strike.","TWN":"可惜沒能一口氣完成收尾。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_ON","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_MONSTER_MINISTRA_DAMAGE_DOWN"},{"id":"L11_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_ON","text":{"KOREA":"그래도 끝났군요.","JPN":"でも終わりましたね。","ENG":"However, it is now over.","TWN":"儘管如此，還是結束了。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_ON","text":{"KOREA":"당신으로부터 들리던 투지의 음색이 더는 들리지 않고 있으니까요.","JPN":"あなたから聞こえていた闘志の音色が途絶えましたから。","ENG":"I no longer hear your fighting spirit that I used to hear within you.","TWN":"我再也聽不到你之前那種趾高氣昂的語氣了。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"정신 차려!! 정신 차리라고, 부전대장……!!","JPN":"しっかりしろ！！　目を覚ませ！！　副戦隊長……！！","ENG":"Wake up!! Wake up, Deputy Commander...!!","TWN":"醒醒！！副戰隊長，你醒醒……！！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L14_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"젠장, 젠장할……!!","JPN":"くそ、くそおおお……！！","ENG":"Dammit! Dammit!","TWN":"該死，該死……！！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_ON","text":{"KOREA":"흐음, 보기보다 구슬픈 음색을 가지고 계시는 군요.","JPN":"ふうん、思ったより切なげな音色をお持ちですね。","ENG":"Hmm, you possess a more sorrowful tone than you seem.","TWN":"嗯，你痛苦的音色聽起來真不錯呢。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_ON","face":"UNIT_PRIDE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_ON","text":{"KOREA":"겉으로는 항상 강한 척하지만, 그 내면에는 항상 후회와 연민을 안고 계시네요.","JPN":"表では強がり続けながらも、常にその内面に後悔と憐憫を抱いている。","ENG":"Perhaps you pretend to be strong on the outside, but always carry with you regret and pity.","TWN":"或許你只是表面上的堅強，但內心卻總是懷有遺憾和憐憫。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_ON","text":{"KOREA":"자, 이리로 오시지요. 제 연주로 그 슬픔을 잊게 해드리겠습니다.","JPN":"さあ、こちらへどうぞ。その悲しみ、私の演奏ですべて忘れさせてあげましょう。","ENG":"Now, come here. I will rid you of your sorrow with my performance.","TWN":"現在，到這裡來吧。我會用我的演奏幫助你忘記悲傷。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"……개소리 집어치워.","JPN":"……ふざけたことぬかしてんじゃねえ。","ENG":"...Cut the crap.","TWN":"……滾開。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"네가 나에 대해서 뭘 안다고 지껄여!?","JPN":"おまえにアタシの何がわかるってんだ！？","ENG":"You think you know everything about me?!","TWN":"你說你了解我什麼？！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L22_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_ON","text":{"KOREA":"……후후.","JPN":"……ふふ。","ENG":"...Fu fuu.","TWN":"……呵呵。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_ON","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_COMBAT_MONSTER_MINISTRA_SKILL_START"},{"id":"L23_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_ON","text":{"KOREA":"원래는 그쪽에 계신 귀빈 분의 소리가 탐이 났는데.","JPN":"先ほどまでは、そちらの方の音が欲しかったのですが。","ENG":"I originally wanted to hear the voice of the VIP over there but...","TWN":"本來我是想聽聽那邊貴賓的聲音。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_ON","text":{"KOREA":"생각이 바뀌었습니다.","JPN":"気が変わりました。","ENG":"I have changed my mind.","TWN":"我改變想法了。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_ON","text":{"KOREA":"당신의 교성이 듣고 싶어졌습니다.","JPN":"あなたの嬌声が聞きたいですね。","ENG":"Now, I wish to hear your screams.","TWN":"現在，我想聽聽你的。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_ON","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"젠장! 이렇게나 필사적으로 여기까지 달려왔는데……!","JPN":"くそ！　こんなに必死になってここまで駆けつけてきたのに……！","ENG":"Dammit! I came here as fast as I could...!","TWN":"該死！我拼命跑到這裡……！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L28_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"결국, 또 늦어버린 거야……? 나란 녀석은 또 아무도 구하지 못하는 거냐고……!","JPN":"また間に合わなかったのか……？　アタシは結局、また誰も救えなかったのか……！","ENG":"But I'm late again...? Am I that incompetent to not even be able to save anyone...?!","TWN":"結果，還是太遲了嗎……？像我這樣的人，誰都救不了……！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"이렇게 무력하게……!! ","JPN":"なんて無力なんだ……！！ ","ENG":"Why am I so weak...?!","TWN":"為什麼我會這麼弱……！！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"타들어 가는 불속에 홀로 살아 남았을 때처럼……! 이렇게 속수무책으로……!","JPN":"炎の中から一人生き残ったあの日みたいに……！　こんな、成す術もないなんて……！","ENG":"Just like when I survived in that burning fire alone...! I can't do anything...!","TWN":"就像我獨自一人在大火中倖存下來的那天一樣……！無能為力……！？"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"BISHOP_REPLACER_NULL_QM","text":{"KOREA":"아니, 자네는 잘 싸워주었다.","JPN":"いや、君はよく戦ってくれた。","ENG":"No, you fought well.","TWN":"不，你做得很好。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"이 목소리는……? 메이즈 전대장님……!?","JPN":"この声は……？　メイズ戦隊長……！？","ENG":"That voice... Maze Commander...?!","TWN":"這聲音……？梅茲戰隊長……？！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"자네가 버텨주었기에 우리가 제때 도착할 수 있었어.","JPN":"君が耐えてくれたおかげで、私たちも間に合った。","ENG":"You were able to hold her here so that we could arrive on time.","TWN":"多虧你的堅持，我們才得以準時到達。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L36_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"감사를 전한다. 앨리스 브레이드우드.","JPN":"礼を言う、アリス・ブレイドウッド。","ENG":"Thank you, Alice Braidwood.","TWN":"謝謝。艾莉絲·布雷德伍德。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"잠깐, 우리라고요……? 그럼 설마……? ","JPN":"私たち……？　ってことは、まさか……？ ","ENG":"Wait, \\"we\\"…? Then…?","TWN":"等等，我們……？難道……？"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"BISHOP_REPLACER_NULL_QM","text":{"KOREA":"비켜 소방관 아줌마!!","JPN":"退いて退いて、消防士のおばさん！！","ENG":"Outta the way, firefighter lady!!","TWN":"消防員阿姨，讓開啦！！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"LEESUYEON_ADMIN_NULL_NULL","text":{"KOREA":"간다! 이 침식체 녀석들아!!","JPN":"行くよー！　侵食体どもめ！！","ENG":"I'm coming for you, you stupid C.O.s!","TWN":"來啊！你們這些侵蝕體！！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"LEESUYEON_ADMIN_NULL_NULL","text":{"KOREA":"이수여어어어언──! 스트라이크으으으으──!","JPN":"カナミ・キズナァァァァ──！　ストラァァァァ──イクッ！","ENG":"Lee Sooyeoooooonnnnn! STRIIIIIKE!!!","TWN":"李秀妍……！絕殺……！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_ON","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_ON","face":"UNIT_HATE"},"R":null}},"sfx":"FX_COMBAT_MONSTER_MINISTRA_DAMAGE_DOWN"},{"id":"L48_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"최고 지휘자님……!","JPN":"マエストロ……！","ENG":"Chief Conductor...!","TWN":"首席指揮家……！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L49_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"관리국이 이곳 필하모닉 홀에 계속해서 지원부대를 보내고 있습니다.","JPN":"このフィルハーモニーホールに、管理局の増援が次々と送られてきています。","ENG":"The Administration is continuously sending reinforcements to Philharmonic Hall.","TWN":"管理局正在向管弦樂廳派遣支援部隊。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"본대가 오기 전에 이곳을 피하셔야 합니다.","JPN":"本隊が来る前にここを離れないといけません。","ENG":"We must retreat before the main fleet arrives.","TWN":"我們必須在主力到來之前離開這個地方。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"단원들의 악기와 이곳의 연구 성과는 회수하였습니다!","JPN":"団員たちの楽器と、ここでの研究成果は無事回収しました！","ENG":"I've already gathered all the instruments and research data!","TWN":"成員們的樂器和研究成果已被找回！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"그러니 어서……!","JPN":"ですから早く……！","ENG":"So...!","TWN":"所以請儘快……！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_ON","text":{"KOREA":"……확실히. 관리국의 귀빈분들께서 하나둘씩 모여들고 있는 게 들리는군요.","JPN":"……確かに、聞こえます。管理局の貴賓が次々と集まってきていますね。","ENG":"...I see. I hear the Administration's VIPs gathering one after another.","TWN":"……嗯。我聽見管理局的貴賓們一一聚集的聲音了。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_ON","face":"UNIT_HATE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_ON","text":{"KOREA":"이대로라면, 저희가 패배할지도 모르겠습니다.","JPN":"このままですと、私たちが負けるかもしれません。","ENG":"We might lose if this continues.","TWN":"再這樣下去，我們可能會輸。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_ON","text":{"KOREA":"오늘은 일단 물러나죠. 셰나.","JPN":"今日は一旦引き下がりましょう、シェナ。","ENG":"Let us retreat, Shena.","TWN":"今天先撤退。世娜."},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"어딜!!","JPN":"させないぞ！！","ENG":"You don't!!","TWN":"你休想！"},"stage":{"bg":"SKY_RED","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"전 대원, 목표는 전방의 제5종 침식체. 마에스트로 네퀴티아……!","JPN":"全隊員、ターゲットは前方の第5種侵食体、マエストロ・ネキティア……！","ENG":"All units, the target is the Category 5 C.O., Maestra Nequitia...!","TWN":"全體隊員注意，目標，前方的5類侵蝕體。指揮家·莉奎蒂亞……！"},"stage":{"bg":"SKY_RED","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"플라즈마 입자 포 발사!! 적을 섬멸하라!!","JPN":"プラズマ粒子砲、発射！！　敵を殲滅せよ！！","ENG":"Fire the plasma particle cannon!! Annihilate the enemy!!","TWN":"發射離子粒子炮！！殲滅敵人！！"},"stage":{"bg":"SKY_RED","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L17_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_ON","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_ON","face":"UNIT_HATE"},"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_DARK_14"},{"id":"L18_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_ON","text":{"KOREA":"하지만 오늘 치욕은 언젠가 갚아드리도록 하죠.","JPN":"ですが、今日のこの恥辱……いつか必ず、お返しします。","ENG":"But someday I'll return the humiliation I endured here today.","TWN":"總有一天，我會讓你們為今日之辱付出代價。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_ON","text":{"KOREA":"……반드시.","JPN":"……必ず。","ENG":"...Most certainly.","TWN":"……一定。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_ON","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};